      "name": "Pipeline_Plan.html",
      "content": "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"UTF-8\">\n<title>Bloc 3: Pipeline Plan</title>\n<style>\n  body { font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif; margin: 0; background: #0f172a; color: white; display: flex; flex-direction: column; align-items: center; justify-content: center; height: 100vh; overflow: hidden; }\n  .presentation-wrapper { display: flex; flex-direction: column; align-items: center; justify-content: center; width: 100%; height: 100%; }\n  .slide-container { width: 900px; height: 500px; background: white; color: #334155; border-radius: 12px; box-shadow: 0 20px 25px -5px rgba(0,0,0,0.1); padding: 50px; position: relative; display: none; box-sizing: border-box; }\n  .slide-container.active { display: flex; flex-direction: column; animation: fadeIn 0.5s; }\n  @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }\n  .header { color: #0f172a; border-bottom: 3px solid #e11d48; padding-bottom: 15px; margin-bottom: 25px; }\n  h1 { margin: 0; font-size: 2.2rem; }\n  h2 { color: #be123c; font-size: 1.5rem; margin-top: 0; }\n  ul { font-size: 1.2rem; line-height: 1.8; color: #475569; }\n  .controls { margin-top: 30px; display: flex; gap: 15px; z-index: 10; }\n  button { padding: 12px 24px; cursor: pointer; background: #e11d48; color: white; border: none; border-radius: 6px; font-weight: bold; font-size: 1rem; }\n  button:hover { background: #be123c; }\n  button:disabled { background: #94a3b8; cursor: not-allowed; }\n  .slide-number { position: absolute; bottom: 20px; right: 30px; font-weight: bold; color: #94a3b8; }\n</style>\n</head>\n<body>\n\n<div class=\"presentation-wrapper\">\n  <div id=\"slides\">\n    <div class=\"slide-container active\">\n        <div class=\"header\"><h1>Aurora Tech: Real-time Pipelines</h1></div>\n        <h2>ETL Pipeline Architecture</h2>\n        <ul>\n            <li><strong>Objective:</strong> Automate data delivery into the data warehouse.</li>\n            <li><strong>Module:</strong> Bloc 3 - Real-time Data Pipelines</li>\n            <li><strong>Tooling:</strong> Apache Airflow, Python</li>\n        </ul>\n        <div class=\"slide-number\">Slide 1 / 5</div>\n    </div>\n    \n    <div class=\"slide-container\">\n        <div class=\"header\"><h1>1. Airflow Orchestration</h1></div>\n        <h2>DAG Design</h2>\n        <ul>\n            <li>Directed Acyclic Graph executes nightly at UTC midnight.</li>\n            <li>Features task dependencies ensuring Extraction concludes before Transformation begins.</li>\n            <li>PythonOperator handles external API calls and business logic execution natively.</li>\n        </ul>\n        <div class=\"slide-number\">Slide 2 / 5</div>\n    </div>\n\n    <div class=\"slide-container\">\n        <div class=\"header\"><h1>2. Data Extraction Strategy</h1></div>\n        <h2>Dual-Stream Ingestion</h2>\n        <ul>\n            <li><strong>Stream A (Financial):</strong> HTTP request to Frankfurter API for EUR/USD rates.</li>\n            <li><strong>Stream B (Logistics):</strong> Internal telemetry simulator generating stochastic container delay data from Taiwan.</li>\n        </ul>\n        <div class=\"slide-number\">Slide 3 / 5</div>\n    </div>\n\n    <div class=\"slide-container\">\n        <div class=\"header\"><h1>3. Transformation & QA</h1></div>\n        <h2>ETL Flow & Business Rules</h2>\n        <div style=\"display:flex; flex-direction:column; align-items:center; gap:10px; margin: 15px 0; font-size: 0.95rem;\">\n            <div style=\"display:flex; gap: 20px;\">\n                <div style=\"background:#e2e8f0; color:#0f172a; padding:10px; border-radius:6px; border:1px solid #94a3b8;\">FX API Data</div>\n                <div style=\"background:#e2e8f0; color:#0f172a; padding:10px; border-radius:6px; border:1px solid #94a3b8;\">Simulator Data</div>\n            </div>\n            <div style=\"color: #e11d48;\">&#11167; Extract & Transform</div>\n            <div style=\"background:#ffe4e6; color:#be123c; padding:10px; border-radius:6px; border:2px dashed #f43f5e; text-align:center;\">\n                <b>QA Decision Tree</b><br/>\n                <small>SeaDelay >= 12 ? &#10141; Force Air Freight (45 EUR) : Keep Sea Freight</small><br/>\n                <small>API Error 500 ? &#10141; Trigger 7-Day Target Moving Avg Fallback</small>\n            </div>\n            <div style=\"color: #e11d48;\">&#11167; Load</div>\n            <div style=\"background:#4f46e5; color:white; padding:10px; border-radius:6px;\">PostgreSQL Star Schema</div>\n        </div>\n        <div class=\"slide-number\">Slide 4 / 5</div>\n    </div>\n\n    <div class=\"slide-container\">\n        <div class=\"header\"><h1>4. Loading and Monitoring</h1></div>\n        <h2>Conclusion</h2>\n        <ul>\n            <li>Processed multidimensional data is loaded into PostgreSQL via psycopg2 connector.</li>\n            <li>Airflow UI provides visual observation of task success/failure.</li>\n            <li>Data is now fully staged and prepared for Machine Learning execution in Bloc 4.</li>\n            <li><strong>Ready for Q&A.</strong></li>\n        </ul>\n        <div class=\"slide-number\">Slide 5 / 5</div>\n    </div>\n  </div>\n  \n  <div class=\"controls\">\n    <button id=\"prevBtn\" onclick=\"prevSlide()\" disabled>Previous Slide</button>\n    <button id=\"nextBtn\" onclick=\"nextSlide()\">Next Slide</button>\n  </div>\n</div>\n\n<script>\n  let currentSlide = 0;\n  const slides = document.querySelectorAll('.slide-container');\n  const prevBtn = document.getElementById('prevBtn');\n  const nextBtn = document.getElementById('nextBtn');\n\n  function showSlide(index) {\n    slides.forEach(s => s.classList.remove('active'));\n    slides[index].classList.add('active');\n    prevBtn.disabled = index === 0;\n    nextBtn.disabled = index === slides.length - 1;\n  }\n  function nextSlide() { if (currentSlide < slides.length - 1) { currentSlide++; showSlide(currentSlide); } }\n  function prevSlide() { if (currentSlide > 0) { currentSlide--; showSlide(currentSlide); } }\n</script>\n</body>\n</html>\n",
