      "name": ".github/workflows/mlops-ci.yml",
      "content": "name: Aurora Tech Chromebook MLOps CI Pipeline\n\non:\n  push:\n    branches: [ main ]\n\njobs:\n  build-and-test:\n    runs-on: ubuntu-latest\n    steps:\n    - name: Checkout Code\n      uses: actions/checkout@v3\n\n    - name: Set up Python\n      uses: actions/setup-python@v4\n      with:\n        python-version: '3.10'\n\n    - name: Install Dependencies\n      run: |\n        pip install scikit-learn joblib fastapi uvicorn pytest pydantic\n\n    - name: Run Automated Quality Gate Tests\n      run: |\n        pytest -v\n",
